import json
import requests


class Client:
    def __init__(self, base_url):
        self._base = base_url

    def list(self, path):
        return requests.get(f"{self._base}/list/{path}").json()

    def download(self, path):
        with open("file", "wb") as fd:
            fd.write(requests.get(f"{self._base}/{path}").content)


class Server:
    def __init__(self, root_dir="."):
        self._root = os.path.normpath(os.path.join(root_dir))

    @staticmethod
    def _make_json(file):
        return {
            "name": file["name"],
            "size": file["size"] if not file["is_dir"] else 0,
            "time": file["time"],
            "children": [
                {"name": f.name} for f in os.scandir(os.path.join(root_dir))
            ],
        }

    def get_info(self, path):
        return self._make_json(path)